export default {
    data() {
        return {
            assertResult: '',
            resultFlag: null,
            resultList: [],
            inputList: [],
        }
    },
    mounted() {
        this.gameNextLevel();
    },
    methods: {
        gameRefreshLevel() {
            this.inputList = this.buildInputList();
            this.resultList = this.buildResultList();
        },
        gameNextLevel() {
            this.assertResult = this.buildAssertResult();
            this.gameRefreshLevel();
        }
    },
    watch: {
        resultList: {
            handler(resultList) {
                const assertResult = resultList.map(e => e.value).join('');
                if (assertResult.length === this.assertResult.length) {
                    this.resultFlag = (assertResult === this.assertResult);
                } else {
                    this.resultFlag = null;
                }
            },
            deep: true
        }
    }
}