<template>
    <TransitionGroup
        tag="div"
        name="main"
        class="main area-main"
    >
        <TileList
          key="result-tile-list"
          class="bg-blue not-disabled"
          :class="{'animation-shake': (resultAnimation === false)}"
          :tileList="resultList"
          @clickTile="(e) => {$emit('clickTileResult', e)}"
        />
        <TileList
          v-if="(resultAnimation !== true)"
          key="input-tile-list"
          class="bg-yellow"
          :tileList="inputList"
          @clickTile="(e) => {$emit('clickTileInput', e)}"
        />
    </TransitionGroup>
    <ControlsPanel
        @clickRefresh="$emit('clickControlRefresh')"
        @clickNext="$emit('clickControlNext')"
    />
</template>

<script>
// import CharList from '@/components/CharList';
import TileList from '@/components/TileList';
import ControlsPanel from '@/components/ControlsPanel';
import DomMixin from '@/mixins/domMixin';
export default {
    mixins: [
      DomMixin,
    ],
    created() {
        this.domSetDocumentBackgroundUrl(require('/public/img/bg-game1-1080p.png'));
    },
    props: ['resultFlag', 'resultList', 'inputList'],
    components: {
        // CharList,
        ControlsPanel,
        TileList,
    },
    emits: ['clickTileResult', 'clickTileInput', 'clickControlRefresh', 'clickControlNext'],
    data() {
        return {
            resultAnimation: true,
            animationTimeout: null,
        }
    },
    mounted() {
      this.resultAnimation = this.resultFlag;
    },
    watch: {
        resultFlag(resultFlag) {
            if (resultFlag !== null) {
                this.animationTimeout = setTimeout(() => {this.resultAnimation = resultFlag}, 500);
            } else {
                if (this.animationTimeout) {
                    clearTimeout(this.animationTimeout);
                    this.animationTimeout = null;
                }
                this.resultAnimation = resultFlag;
            }
        }
    }
}
</script>

<style>
.main {

    display: flex;
    flex-direction: column;
    justify-content: center;
}

.char-list {
  width: 100%;
  box-sizing: border-box;
}

.tile-list {
  width: 100%;
  box-sizing: border-box;
}

.tile-list.not-disabled .tile-item.disabled, .tile-list.not-disabled .tile-item.disabled .tile-content {
  opacity: 1;
}

.main-move,
.main-enter-active,
.main-leave-active {
  transition: all 1s ease;
}

.main-enter-from,
.main-leave-to {
  opacity: 0;
  transform: scale(0.8);
}
.main-leave-active {
  position: absolute;
}

.animation-shake {
  animation: animation-shake 0.8s cubic-bezier(0.36, 0.07, 0.19, 0.97) both;
}

@keyframes animation-shake {
  10%,
  90% {
    transform: translateX(-0.25vw);
  }

  20%,
  80% {
    transform: translateX(0.5vw);
  }

  30%,
  50%,
  70% {
    transform: translateX(-1vw);
  }

  40%,
  60% {
    transform: translateX(1vw);
  }
}
</style>